import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Loader2, ImageIcon, Sparkles, Database, Trash, ArrowLeft, 
  Tag, Eye, Edit2, Check, X, Calendar, ShoppingBasket 
} from 'lucide-react';
import SubirImagenes from './SubirImagenes'; // <--- IMPORTANTE: Asegúrate que el archivo exista

const API_URL = "http://localhost:5000"; 
const CLOUD_NAME = "dwpgncjgn";

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();

  const filaInicial = () => ({ 
    id: Math.random(), producto: '', precioNuevo: '', precioViejo: '', stock: '', categoria: 'Almacén', fotoSugerida: null 
  });
  
  const [filas, setFilas] = useState([filaInicial()]);
  const [publicados, setPublicados] = useState([]);
  const [galeria, setGaleria] = useState([]);
  const [fechas, setFechas] = useState({ inicio: '', fin: '' });
  const [cargando, setCargando] = useState(false);
  const [editandoId, setEditandoId] = useState(null);
  const [tempData, setTempData] = useState({});

  const cargarDatos = useCallback(async () => {
    try {
      const [resOfertas, resGaleria] = await Promise.all([
        axios.get(`${API_URL}/api/ofertas/local/${localId}`),
        axios.get(`${API_URL}/api/galeria`)
      ]);
      setPublicados(resOfertas.data || []);
      setGaleria(resGaleria.data || []);
    } catch (e) { console.error("Error al sincronizar", e); }
  }, [localId]);

  useEffect(() => { cargarDatos(); }, [cargarDatos]);

  const buscarMatch = useCallback((texto) => {
    if (!texto || texto.length < 3) return null;
    const norm = (t) => t.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-z0-9]/g, '');
    const textoLimpio = norm(texto);
    return galeria.find(f => norm(f.nombreReferencia).includes(textoLimpio) || textoLimpio.includes(norm(f.nombreReferencia)));
  }, [galeria]);

  const handlePaste = (e) => {
    e.preventDefault();
    const data = e.clipboardData.getData('Text');
    const lineas = data.split(/\r?\n/).filter(l => l.trim() !== '');
    const nuevas = lineas.map(line => {
      const c = line.split('\t');
      const nombre = c[0]?.trim() || '';
      const m = buscarMatch(nombre);
      return { 
        id: Math.random(), producto: nombre, precioNuevo: c[1] || '', 
        precioViejo: c[2] || '', stock: c[3] || 0, categoria: c[4] || 'Almacén', 
        fotoSugerida: m ? m.publicId : null 
      };
    });
    setFilas(nuevas);
  };

  const handleInputChange = (id, campo, valor) => {
    setFilas(filas.map(f => {
      if (f.id === id) {
        const act = { ...f, [campo]: valor };
        if (campo === 'producto') {
          const m = buscarMatch(valor);
          act.fotoSugerida = m ? m.publicId : null;
        }
        return act;
      }
      return f;
    }));
  };

  const publicarTodo = async () => {
    if (!fechas.inicio || !fechas.fin) return alert("Selecciona fechas de validez.");
    const validas = filas.filter(f => f.producto && f.precioNuevo);
    if (validas.length === 0) return alert("No hay productos válidos.");

    setCargando(true);
    try {
      // USAMOS LA RUTA /BULK QUE ES MÁS RÁPIDA
      const productos = validas.map(f => ({
        producto: f.producto,
        precioNuevo: f.precioNuevo,
        precioViejo: f.precioViejo || f.precioNuevo,
        stock: f.stock,
        categoria: f.categoria,
        publicId: f.fotoSugerida || 'placeholder_id',
        fechaInicioOferta: fechas.inicio,
        fechaFinOferta: fechas.fin,
        publicado: true
      }));

      await axios.post(`${API_URL}/api/ofertas/bulk`, { localId, productos });
      alert("¡Lote publicado!");
      setFilas([filaInicial()]);
      cargarDatos();
    } catch (e) { alert("Error al publicar."); } 
    finally { setCargando(false); }
  };

  const renderFoto = (pid, size = "w_50,h_50") => (
    <div style={{ width: 50, height: 50, background: '#f1f5f9', borderRadius: 8, overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      {(!pid || pid === 'placeholder_id') ? <ImageIcon color="#cbd5e1" size={20}/> : 
      <img src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/${size},c_fill/f_auto,q_auto/v1/${pid}`} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />}
    </div>
  );

  return (
    <div style={{ padding: '30px', maxWidth: '1300px', margin: '0 auto', background: '#f8fafc', minHeight: '100vh' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '30px' }}>
        <button onClick={() => navigate(-1)} style={btnBack}><ArrowLeft size={18}/> Volver</button>
        {/* AQUÍ ESTÁ LA MAGIA: EL COMPONENTE REAL DE SUBIDA */}
        <SubirImagenes onFinished={cargarDatos} />
      </div>

      <section style={cardContainer} onPaste={handlePaste}>
        <div style={cardHeader}>
          <div style={{ color: '#e67e22', fontWeight: 'bold' }}><Sparkles size={20}/> Carga Masiva</div>
          <button onClick={() => setFilas([...filas, filaInicial()])} style={btnAddRow}><Plus size={16}/> Fila Manual</button>
        </div>
        <table style={tableStyle}>
          <thead>
            <tr style={tableHead}>
              <th style={thStyle}>Foto</th><th style={thStyle}>Producto</th><th style={thStyle}>$ Oferta</th><th style={thStyle}>Stock</th><th style={{width: 50}}></th>
            </tr>
          </thead>
          <tbody>
            {filas.map(f => (
              <tr key={f.id} style={trStyle}>
                <td style={tdStyle}>{renderFoto(f.fotoSugerida)}</td>
                <td style={tdStyle}><input style={inputTable} value={f.producto} placeholder="Nombre..." onChange={e => handleInputChange(f.id, 'producto', e.target.value)}/></td>
                <td style={tdStyle}><input style={inputNum} type="number" value={f.precioNuevo} onChange={e => handleInputChange(f.id, 'precioNuevo', e.target.value)}/></td>
                <td style={tdStyle}><input style={inputNum} type="number" value={f.stock} onChange={e => handleInputChange(f.id, 'stock', e.target.value)}/></td>
                <td style={tdStyle}><button onClick={() => setFilas(filas.filter(x => x.id !== f.id))} style={{border:'none', background:'none', cursor:'pointer'}}><X size={18} color="#94a3b8"/></button></td>
              </tr>
            ))}
          </tbody>
        </table>
        <div style={cardFooter}>
          <div style={{ display: 'flex', gap: 10 }}>
            <input type="date" value={fechas.inicio} onChange={e => setFechas({...fechas, inicio: e.target.value})} style={inputDate}/>
            <input type="date" value={fechas.fin} onChange={e => setFechas({...fechas, fin: e.target.value})} style={inputDate}/>
          </div>
          <button onClick={publicarTodo} style={btnPublish} disabled={cargando}>{cargando ? <Loader2 className="animate-spin"/> : <Sparkles size={18}/>} PUBLICAR TODO</button>
        </div>
      </section>

      {/* PRODUCTOS PUBLICADOS */}
      <div style={gridStyle}>
        {publicados.map(p => (
          <div key={p._id} style={itemCard}>
            <button onClick={async () => { if(window.confirm("¿Borrar?")){ await axios.delete(`${API_URL}/api/ofertas/${p._id}`); cargarDatos(); }}} style={btnCircleRed}><Trash size={14}/></button>
            <div style={itemPreview}>{renderFoto(p.publicId, "w_200,h_150")}</div>
            <h4 style={itemTitle}>{p.producto}</h4>
            <div style={itemPrice}>${p.precioNuevo}</div>
          </div>
        ))}
      </div>
    </div>
  );
};

// ESTILOS (Mantenemos los tuyos con ajustes menores)
const btnBack = { background: 'none', border: 'none', color: '#64748b', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' };
const cardContainer = { background: 'white', borderRadius: '20px', border: '1px solid #e2e8f0', overflow: 'hidden', marginBottom: '40px' };
const cardHeader = { padding: '20px', borderBottom: '1px solid #f1f5f9', display: 'flex', justifyContent: 'space-between' };
const btnAddRow = { background: '#f1f5f9', border: 'none', padding: '8px 15px', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' };
const tableStyle = { width: '100%', borderCollapse: 'collapse' };
const tableHead = { background: '#f8fafc' };
const thStyle = { padding: '15px', textAlign: 'left', color: '#64748b', fontSize: '0.75rem' };
const trStyle = { borderBottom: '1px solid #f1f5f9' };
const tdStyle = { padding: '12px 15px' };
const inputTable = { width: '100%', border: 'none', outline: 'none', background: 'transparent' };
const inputNum = { width: '70px', padding: '5px', border: '1px solid #eee', borderRadius: '4px' };
const cardFooter = { padding: '20px', display: 'flex', justifyContent: 'space-between', background: '#f8fafc' };
const inputDate = { padding: '8px', borderRadius: '8px', border: '1px solid #e2e8f0' };
const btnPublish = { background: '#e67e22', color: 'white', padding: '10px 25px', borderRadius: '10px', border: 'none', cursor: 'pointer', fontWeight: 'bold', display: 'flex', gap: 8 };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '20px' };
const itemCard = { background: 'white', padding: '15px', borderRadius: '20px', border: '1px solid #e2e8f0', position: 'relative' };
const itemPreview = { height: '120px', display: 'flex', justifyContent: 'center', alignItems: 'center', marginBottom: '10px' };
const itemTitle = { margin: '5px 0', fontSize: '0.9rem', color: '#1e293b' };
const itemPrice = { fontWeight: 'bold', color: '#e67e22' };
const btnCircleRed = { position: 'absolute', top: 10, right: 10, background: '#fee2e2', border: 'none', borderRadius: '50%', width: '30px', height: '30px', cursor: 'pointer', color: '#ef4444', display:'flex', alignItems:'center', justifyContent:'center' };

export default GestionOfertas;
